from __future__ import annotations

"""01 내용 이미지 업로드 노드.

STANDALONE 컴포넌트로 동작하도록 필요한 이미지 변환/배치 로직을
이 파일 안에 모두 포함합니다. 같은 폴더의 다른 .py 파일을 import하지 않습니다.
"""

import base64
import mimetypes
import re
from copy import deepcopy
from pathlib import Path
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, FileInput, Output
from lfx.schema.data import Data


ALLOWED_IMAGE_PREFIXES = ("data:image/png;base64,", "data:image/jpeg;base64,", "data:image/webp;base64,")
DEFAULT_MAX_IMAGE_BYTES = 5 * 1024 * 1024


def attach_content_images(payload_value: Any, content_image_files: Any) -> dict[str, Any]:
    """내용 이미지를 base64 data URI로 바꾸고 페이지 배치를 자동 계산합니다."""

    payload = _ensure_flow_payload(_payload(payload_value))
    request = _dict(payload.get("deck_request"))
    image_assets, image_warnings = _collect_uploaded_page_images(content_image_files)
    placement_text = _clean_preserve(request.get("image_placement_instruction"))
    placements, placement_warnings = _build_image_placements(image_assets, request, placement_text)

    result = deepcopy(payload)
    result["image_assets"] = {"assets": image_assets}
    result["image_placements"] = placements
    result["trace"] = _merge_trace(result.get("trace"), [*image_warnings, *placement_warnings], [])
    result["image_bundle_summary"] = {
        "image_count": len(image_assets),
        "placement_count": len(placements),
        "warnings": [*image_warnings, *placement_warnings],
    }
    return result


def _collect_uploaded_page_images(content_image_files: Any) -> tuple[list[dict[str, Any]], list[str]]:
    """업로드 파일을 내용 이미지 asset 목록으로 변환합니다."""

    raw_images, warnings = _collect_uploaded_images(content_image_files)
    assets: list[dict[str, Any]] = []
    seen_keys: set[str] = set()
    for index, image in enumerate(raw_images, start=1):
        data_uri = _clean(image.get("data_uri"))
        filename = _clean(image.get("filename"))
        seen_key = "|".join([filename, data_uri])
        if not data_uri or seen_key in seen_keys:
            continue
        seen_keys.add(seen_key)
        image_ref = _safe_ref(filename or f"img{index}")
        image_id = _safe_id(image_ref or f"img{index}") or f"img{index}"
        assets.append(
            {
                "image_id": image_id,
                "image_ref": image_ref or image_id,
                "filename": filename,
                "data_uri": data_uri,
                "mime_type": _clean(image.get("mime_type")) or _mime_from_data_uri(data_uri),
                "width": int(image.get("width") or 0),
                "height": int(image.get("height") or 0),
                "size_bytes": int(image.get("size_bytes") or 0),
                "page_hint": _page_from_filename(filename),
                "source": "content_upload",
                "alt": _alt_from_filename(filename, image_id),
            }
        )
    return assets, warnings


def _collect_uploaded_images(files_value: Any) -> tuple[list[dict[str, Any]], list[str]]:
    """Langflow FileInput 값 하나 또는 여러 개를 이미지 dict 목록으로 바꿉니다."""

    warnings: list[str] = []
    images: list[dict[str, Any]] = []
    for candidate in _candidate_values(files_value):
        image, warning = _image_from_candidate(candidate, DEFAULT_MAX_IMAGE_BYTES)
        if warning:
            warnings.append(warning)
        if image:
            images.append(image)
    return images, warnings


def _image_from_candidate(candidate: Any, max_bytes: int) -> tuple[dict[str, Any], str]:
    """파일 객체, 경로, bytes, data URI 중 하나를 이미지 dict로 바꿉니다."""

    if candidate in (None, ""):
        return {}, ""
    if isinstance(candidate, dict):
        data_uri = _clean(candidate.get("data_uri") or candidate.get("src"))
        if _valid_data_uri(data_uri):
            try:
                _, encoded = data_uri.split(",", 1)
                raw = base64.b64decode(encoded, validate=True)
            except Exception:
                return {}, "data URI base64를 디코딩하지 못했습니다."
            filename = _clean(candidate.get("filename") or candidate.get("name"))
            image, warning = _image_from_bytes(raw, filename, max_bytes)
            if image:
                image["data_uri"] = data_uri
                image["source"] = "data_uri"
            return image, warning

    raw, filename, read_warning = _read_image_bytes(candidate)
    if read_warning:
        return {}, read_warning
    if raw is not None:
        return _image_from_bytes(raw, filename, max_bytes)

    text = _clean(candidate)
    if not text:
        return {}, ""
    if _valid_data_uri(text):
        try:
            _, encoded = text.split(",", 1)
            raw = base64.b64decode(encoded, validate=True)
        except Exception:
            return {}, "data URI base64를 디코딩하지 못했습니다."
        image, warning = _image_from_bytes(raw, "", max_bytes)
        if image:
            image["data_uri"] = text
            image["source"] = "data_uri"
        return image, warning

    path = Path(text)
    if path.is_file():
        return _image_from_path(path, max_bytes)
    return {}, ""


def _read_image_bytes(candidate: Any) -> tuple[bytes | None, str, str]:
    """Langflow FileInput이 넘기는 다양한 객체 형태에서 bytes와 파일명을 꺼냅니다."""

    if isinstance(candidate, bytes):
        return candidate, "", ""
    if isinstance(candidate, bytearray):
        return bytes(candidate), "", ""
    if isinstance(candidate, Path):
        try:
            return candidate.read_bytes(), candidate.name, ""
        except Exception as exc:
            return None, "", f"이미지 파일을 읽지 못했습니다: {exc}"
    if isinstance(candidate, dict):
        filename = _clean(candidate.get("filename") or candidate.get("name") or candidate.get("path") or candidate.get("file_path"))
        for key in ("bytes", "content", "data"):
            raw = candidate.get(key)
            if isinstance(raw, str):
                raw = raw.encode("utf-8")
            if isinstance(raw, (bytes, bytearray)):
                return bytes(raw), Path(filename).name if filename else "", ""
        for key in ("path", "file_path", "filepath"):
            path_text = _clean(candidate.get(key))
            if path_text and Path(path_text).is_file():
                try:
                    return Path(path_text).read_bytes(), Path(path_text).name, ""
                except Exception as exc:
                    return None, "", f"이미지 파일을 읽지 못했습니다: {exc}"
        return None, filename, ""
    read = getattr(candidate, "read", None)
    if callable(read):
        try:
            raw = read()
        except Exception as exc:
            return None, "", f"업로드 이미지 파일을 읽지 못했습니다: {exc}"
        if isinstance(raw, str):
            raw = raw.encode("utf-8")
        if not isinstance(raw, (bytes, bytearray)):
            return None, "", "업로드 파일이 bytes를 반환하지 않았습니다."
        filename = _clean(getattr(candidate, "name", "")) or _clean(getattr(candidate, "filename", ""))
        return bytes(raw), Path(filename).name if filename else "", ""
    return None, "", ""


def _image_from_path(path: Path, max_bytes: int) -> tuple[dict[str, Any], str]:
    try:
        raw = path.read_bytes()
    except Exception as exc:
        return {}, f"이미지 파일을 읽지 못했습니다: {exc}"
    return _image_from_bytes(raw, path.name, max_bytes)


def _image_from_bytes(raw: bytes, filename: str, max_bytes: int) -> tuple[dict[str, Any], str]:
    if len(raw) > max_bytes:
        return {}, f"이미지가 너무 큽니다. 최대 {max_bytes} bytes, 현재 {len(raw)} bytes"
    mime_type = _mime_from_bytes(raw) or mimetypes.guess_type(filename)[0] or ""
    if mime_type not in {"image/png", "image/jpeg", "image/webp"}:
        return {}, "PNG/JPEG/WebP 이미지만 사용할 수 있습니다."
    width, height = _image_size(raw, mime_type)
    return {
        "filename": filename,
        "mime_type": mime_type,
        "data_uri": f"data:{mime_type};base64,{base64.b64encode(raw).decode('ascii')}",
        "width": width,
        "height": height,
        "size_bytes": len(raw),
    }, ""


def _build_image_placements(
    assets: list[dict[str, Any]],
    request: dict[str, Any],
    placement_text: str,
) -> tuple[list[dict[str, Any]], list[str]]:
    """자연어 지시, 파일명, 페이지 image_ref 순서로 내용 이미지 배치를 정합니다."""

    warnings: list[str] = []
    placements = _placements_from_numbers(assets, placement_text)

    for asset in assets:
        if _has_image_placement(placements, asset["image_id"]):
            continue
        page_hint = _positive_int(asset.get("page_hint"), 0)
        if page_hint:
            placements = _upsert_placement(placements, _placement(asset["image_id"], page_hint, asset.get("alt")))

    image_ref_map = _image_ref_map(assets)
    for page in _list(request.get("pages")):
        if not isinstance(page, dict):
            continue
        page_no = _positive_int(page.get("page"), 0)
        for ref in _strings(page.get("image_refs")):
            image_id = image_ref_map.get(_safe_ref(ref))
            if page_no and image_id and not _has_image_placement(placements, image_id):
                placements = _upsert_placement(placements, _placement(image_id, page_no, ref))

    placements = _auto_place_remaining_images(placements, assets, request)
    valid_ids = {asset["image_id"] for asset in assets}
    placements = [item for item in placements if item.get("image_id") in valid_ids and _positive_int(item.get("page"), 0)]
    if assets and not placements:
        warnings.append("이미지가 업로드되었지만 배치할 페이지를 찾지 못했습니다.")
    return placements, warnings


def _placements_from_numbers(assets: list[dict[str, Any]], text: str) -> list[dict[str, Any]]:
    """'이미지 4개를 각각 1, 3, 4, 5페이지' 같은 자연어 지시를 처리합니다."""

    if not assets or not text:
        return []
    numbers = [int(item) for item in re.findall(r"\d{1,2}", text)]
    if len(numbers) < len(assets):
        return []
    page_numbers = numbers[-len(assets) :]
    return [_placement(asset["image_id"], page_numbers[index], asset.get("alt")) for index, asset in enumerate(assets)]


def _auto_place_remaining_images(
    placements: list[dict[str, Any]],
    assets: list[dict[str, Any]],
    request: dict[str, Any],
) -> list[dict[str, Any]]:
    """아직 배치되지 않은 이미지는 중간 페이지부터 순서대로 넣습니다."""

    total = max(_positive_int(request.get("requested_page_count"), 0), 3)
    candidate_pages = list(range(2, total)) or [1]
    used_pages = {_positive_int(item.get("page"), 0) for item in placements}
    page_cursor = 0
    result = list(placements)
    for asset in assets:
        if _has_image_placement(result, asset["image_id"]):
            continue
        while page_cursor < len(candidate_pages) and candidate_pages[page_cursor] in used_pages:
            page_cursor += 1
        page = candidate_pages[page_cursor] if page_cursor < len(candidate_pages) else min(total, len(result) + 1)
        used_pages.add(page)
        result = _upsert_placement(result, _placement(asset["image_id"], page, asset.get("alt")))
    return result


def _candidate_values(value: Any) -> list[Any]:
    """Langflow FileInput/Data/list/dict 입력을 후보 파일 값 목록으로 펼칩니다."""

    if value is None:
        return []
    data = getattr(value, "data", None)
    if data is not None and data is not value:
        nested = _candidate_values(data)
        if nested:
            return nested
    if isinstance(value, list):
        result: list[Any] = []
        for item in value:
            result.extend(_candidate_values(item))
        return result
    if isinstance(value, dict):
        if any(key in value for key in ("bytes", "content", "data", "data_uri", "src")):
            return [value]
        if any(key in value for key in ("path", "file_path", "filepath")) and any(key in value for key in ("filename", "name")):
            return [value]
        result: list[Any] = []
        for key in ("files", "file", "images", "image", "path", "file_path", "filepath", "data_uri", "value", "content", "data"):
            if key in value:
                result.extend(_candidate_values(value[key]))
        return result or [value]
    for attr in ("files", "file", "path", "file_path", "filepath", "location", "content", "text", "value"):
        nested = getattr(value, attr, None)
        if nested is not None and nested is not value:
            candidates = _candidate_values(nested)
            if candidates:
                return candidates
    return [value]


def _ensure_flow_payload(value: dict[str, Any]) -> dict[str, Any]:
    """00을 건너뛰고 00-2의 deck_request가 바로 들어와도 flow payload로 감쌉니다."""

    payload = deepcopy(value) if isinstance(value, dict) else {}
    if isinstance(payload.get("deck_request"), dict):
        payload.setdefault("payload_version", "card-news-ver2")
        payload.setdefault("flow_type", "card_news_ver2")
        payload.setdefault("image_assets", {"assets": []})
        payload.setdefault("image_placements", [])
        payload.setdefault("character_assets", {})
        payload.setdefault("card_news_plan", {})
        payload.setdefault("html_result", {})
        payload.setdefault("trace", {"warnings": [], "errors": []})
        return payload
    if _looks_like_deck_request(payload):
        return {
            "payload_version": "card-news-ver2",
            "flow_type": "card_news_ver2",
            "request_id": "card_news_v2_from_structured_input",
            "deck_request": payload,
            "image_assets": {"assets": []},
            "image_placements": [],
            "character_assets": {},
            "card_news_plan": {},
            "html_result": {},
            "trace": {"warnings": [], "errors": []},
        }
    return payload


def _looks_like_deck_request(value: dict[str, Any]) -> bool:
    if not isinstance(value, dict):
        return False
    request_keys = {
        "series_title",
        "issue_label",
        "issue_no",
        "cover",
        "pages",
        "closing",
        "requested_page_count",
        "image_placement_instruction",
    }
    return bool(request_keys.intersection(value.keys()))


def _placement(image_id: str, page: int, alt: Any) -> dict[str, Any]:
    return {
        "image_id": image_id,
        "page": page,
        "mode": "",
        "fit": "contain",
        "alt": _clean(alt),
    }


def _image_ref_map(assets: list[dict[str, Any]]) -> dict[str, str]:
    result: dict[str, str] = {}
    for asset in assets:
        image_id = asset["image_id"]
        refs = [asset.get("image_id"), asset.get("image_ref"), asset.get("filename"), Path(_clean(asset.get("filename"))).stem]
        for ref in refs:
            safe = _safe_ref(ref)
            if safe:
                result[safe] = image_id
    return result


def _upsert_placement(items: list[dict[str, Any]], placement: dict[str, Any]) -> list[dict[str, Any]]:
    image_id = _clean(placement.get("image_id"))
    result = [item for item in items if _clean(item.get("image_id")) != image_id]
    result.append(placement)
    return result


def _has_image_placement(items: list[dict[str, Any]], image_id: str) -> bool:
    return any(_clean(item.get("image_id")) == image_id for item in items)


def _mime_from_bytes(raw: bytes) -> str:
    if raw.startswith(b"\x89PNG\r\n\x1a\n"):
        return "image/png"
    if raw.startswith(b"\xff\xd8"):
        return "image/jpeg"
    if raw[:4] == b"RIFF" and raw[8:12] == b"WEBP":
        return "image/webp"
    return ""


def _image_size(raw: bytes, mime_type: str) -> tuple[int, int]:
    if mime_type == "image/png" and len(raw) >= 24:
        return int.from_bytes(raw[16:20], "big"), int.from_bytes(raw[20:24], "big")
    if mime_type == "image/jpeg":
        index = 2
        while index + 9 < len(raw):
            if raw[index] != 0xFF:
                index += 1
                continue
            marker = raw[index + 1]
            length = int.from_bytes(raw[index + 2 : index + 4], "big")
            if marker in {0xC0, 0xC2} and index + 8 < len(raw):
                return int.from_bytes(raw[index + 7 : index + 9], "big"), int.from_bytes(raw[index + 5 : index + 7], "big")
            index += max(2, length + 2)
    return 0, 0


def _page_from_filename(filename: Any) -> int:
    name = _clean(filename).replace("\\", "/").split("/")[-1].lower()
    patterns = [
        r"(?:page|p|slide|card|screen|페이지|화면|카드)[-_ ]?(\d{1,2})",
        r"(\d{1,2})[-_ ]?(?:page|p|slide|card|screen|페이지|화면|카드)",
        r"^(\d{1,2})[-_ ]",
    ]
    for pattern in patterns:
        match = re.search(pattern, name)
        if match:
            return _positive_int(match.group(1), 0)
    return 0


def _alt_from_filename(filename: str, image_id: str) -> str:
    stem = Path(filename).stem if filename else image_id
    return stem.replace("_", " ").replace("-", " ").strip() or "카드뉴스 이미지"


def _safe_ref(value: Any) -> str:
    text = _clean(value).lower().replace("\\", "/").split("/")[-1]
    text = re.sub(r"\.[a-z0-9]{2,5}$", "", text)
    return re.sub(r"[^a-z0-9가-힣 _-]+", "", text).replace(" ", "_").strip("_-")


def _safe_id(value: Any) -> str:
    text = _safe_ref(value)
    text = re.sub(r"[^a-z0-9_]+", "_", text).strip("_")
    return text[:80]


def _valid_data_uri(value: str) -> bool:
    return bool(value) and value.startswith(ALLOWED_IMAGE_PREFIXES) and "PUT_BASE64" not in value


def _mime_from_data_uri(value: str) -> str:
    match = re.match(r"^data:([^;]+);base64,", value)
    return match.group(1) if match else ""


def _merge_trace(trace_value: Any, warnings: list[str], errors: list[str]) -> dict[str, Any]:
    trace = _dict(trace_value)
    trace["warnings"] = _dedupe([*_list(trace.get("warnings")), *warnings])
    trace["errors"] = _dedupe([*_list(trace.get("errors")), *errors])
    return trace


def _payload(value: Any) -> dict[str, Any]:
    data = getattr(value, "data", value)
    value = data if data is not None else value
    return deepcopy(value) if isinstance(value, dict) else {}


def _dict(value: Any) -> dict[str, Any]:
    return deepcopy(value) if isinstance(value, dict) else {}


def _list(value: Any) -> list[Any]:
    return deepcopy(value) if isinstance(value, list) else []


def _strings(value: Any) -> list[str]:
    raw_items = value if isinstance(value, list) else ([value] if value not in (None, "") else [])
    return _dedupe(_clean(item) for item in raw_items)


def _dedupe(items: Any) -> list[str]:
    result: list[str] = []
    for item in items:
        text = _clean(item)
        if text and text not in result:
            result.append(text)
    return result


def _positive_int(value: Any, default: int) -> int:
    try:
        parsed = int(value)
    except Exception:
        return default
    return max(0, parsed)


def _clean(value: Any) -> str:
    return str(value or "").strip()


def _clean_preserve(value: Any) -> str:
    text = str(value or "").strip()
    return re.sub(r"\n{3,}", "\n\n", text)


class ContentImageUploadBuilder(Component):
    """내용 이미지 파일을 업로드받아 페이지별 이미지 payload를 만드는 Langflow 노드입니다."""

    display_name = "01 내용 이미지 업로드/자동 배치"
    description = "내용에 들어갈 이미지 파일만 업로드하면 base64로 변환하고, 페이지 지시에 맞춰 자동 배치합니다."
    icon = "Images"
    name = "ContentImageUploadBuilder"

    inputs = [
        DataInput(name="payload", display_name="카드뉴스 요청 payload", required=True),
        FileInput(
            name="content_image_files",
            display_name="내용 이미지 파일 업로드",
            info="PNG/JPEG/WebP 파일을 업로드하세요. 여러 파일이 들어오면 파일명, LLM 이미지 배치 지시, image_ref를 기준으로 자동 배치합니다.",
            file_types=["png", "jpg", "jpeg", "webp"],
            # 여러 이미지를 한 번에 업로드할 수 있도록 Langflow 입력을 리스트 모드로 둡니다.
            list=True,
            value=[],
            required=False,
        ),
    ]
    outputs = [Output(name="payload_out", display_name="내용 이미지 포함 payload", method="build_payload", types=["Data"])]

    def build_payload(self) -> Data:
        result = attach_content_images(
            getattr(self, "payload", None),
            getattr(self, "content_image_files", None),
        )
        summary = result.get("image_bundle_summary", {})
        self.status = {
            "내용 이미지 수": summary.get("image_count", 0),
            "이미지 배치 수": summary.get("placement_count", 0),
            "경고 수": len(summary.get("warnings", [])),
        }
        return Data(data=result)

from __future__ import annotations

"""02 카드뉴스 덱 자동 기획 노드.

페이지 내용, 이미지 배치, 꾸미기 asset을 바탕으로 템플릿과 캐릭터 배치를
규칙 기반으로 자동 결정합니다.
"""

import re
from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, MessageTextInput, Output
from lfx.schema.data import Data


ALLOWED_ROLES = {"cover", "why", "case", "tip", "checklist", "security", "workflow", "metric", "recap", "closing"}
ALLOWED_LAYOUTS = {"cover", "text_focus", "image_side", "image_focus", "checklist", "notice", "metric", "closing"}
SECURITY_WORDS = ("보안", "개인정보", "기밀", "민감", "사내", "주의", "금지", "외부")
TIP_WORDS = ("팁", "방법", "체크", "실천", "가이드", "프롬프트", "작성")
WORKFLOW_WORDS = ("자동화", "업무", "프로세스", "흐름", "단계", "절차")
METRIC_WORDS = ("%", "건", "명", "회", "지표", "수치", "증가", "감소", "효율")


def build_card_news_deck_plan(image_payload_value: Any, character_placement_mode: Any = "auto_rule") -> dict[str, Any]:
    """요청/이미지/캐릭터 정보를 합쳐 최종 렌더링 계획을 만듭니다."""

    payload = _payload(image_payload_value)
    request = _dict(payload.get("deck_request"))
    total_pages = max(_positive_int(request.get("requested_page_count"), 0), 3)
    page_specs = _page_spec_map(request)
    image_assets = _image_asset_map(payload)
    placements = _placements_by_page(payload)
    character_manifest = _dict(payload.get("character_assets"))
    character_assets = _character_assets(character_manifest)
    role_defaults = _dict(character_manifest.get("slide_role_defaults"))
    used_character_ids: list[str] = []

    slides = []
    for page_no in range(1, total_pages + 1):
        spec = page_specs.get(page_no, {})
        if page_no == 1:
            slide = _cover_slide(page_no, total_pages, request, spec)
        elif page_no == total_pages:
            slide = _closing_slide(page_no, total_pages, request, spec)
        else:
            slide = _middle_slide(page_no, total_pages, request, spec)

        image = _image_for_page(page_no, total_pages, placements, image_assets, slide["role"], slide["layout"])
        if image:
            slide["image"] = image
            slide["layout"] = _layout_with_image(slide["role"], slide["layout"], image)

        # 캐릭터는 페이지 역할과 이미지 유무를 보고 겹치지 않는 위치로 배치합니다.
        if _clean(character_placement_mode) != "manual":
            character = _select_character(slide, character_assets, role_defaults, used_character_ids)
            if character:
                character["placement"] = _character_placement(slide, image)
                character["size"] = _character_size(slide)
                used_character_ids.append(character["asset_id"])
                slide["character"] = character

        slides.append(slide)

    result = deepcopy(payload)
    result["card_news_plan"] = {
        "plan_version": "card-news-ver2-plan",
        "title": _clean(_dict(request.get("cover")).get("title")) or "카드뉴스",
        "series_title": _clean(request.get("series_title")) or "P&T AI INSIGHT",
        "issue_label": _clean(request.get("issue_label")),
        "issue_no": _clean(request.get("issue_no")),
        "publisher": _clean(request.get("publisher")) or "SK hynix",
        "page_count": len(slides),
        "aspect_ratio": "16:9",
        "slides": slides,
        "used_character_assets": _dedupe(used_character_ids),
        "navigation": {"mode": "screen_transition", "one_file_html": True},
    }
    result["trace"] = _merge_trace(result.get("trace"), [], [])
    return result


def _cover_slide(page_no: int, total_pages: int, request: dict[str, Any], spec: dict[str, Any]) -> dict[str, Any]:
    """첫 페이지는 발행 정보가 잘 보이는 표지 템플릿으로 고정합니다."""

    cover = _dict(request.get("cover"))
    title = _clean(spec.get("title")) or _clean(cover.get("title")) or "이번 달 AI 소식"
    subtitle = _clean(spec.get("content")) or _clean(cover.get("subtitle")) or "꼭 필요한 내용만 카드뉴스로 정리했습니다."
    return {
        "slide_id": f"slide-{page_no}",
        "page": page_no,
        "page_label": f"{page_no:02d} / {total_pages:02d}",
        "role": "cover",
        "layout": "cover",
        "title": title,
        "subtitle": subtitle,
        "body": "",
        "bullets": _strings(spec.get("bullets")),
        "badge": _issue_badge(request),
        "image_refs": _strings(spec.get("image_refs") or cover.get("image_ref")),
        "character": {},
    }


def _middle_slide(page_no: int, total_pages: int, request: dict[str, Any], spec: dict[str, Any]) -> dict[str, Any]:
    """중간 페이지는 내용 성격에 따라 역할과 레이아웃을 고릅니다."""

    title = _clean(spec.get("title"))
    subtitle = _clean(spec.get("subtitle") or spec.get("sub_title") or spec.get("summary"))
    body = _clean_preserve(spec.get("body") or spec.get("content"))
    bullets = _strings(spec.get("bullets"))
    role = _safe_token(spec.get("role") or _infer_role(title, " ".join([subtitle, body]), bullets, page_no), ALLOWED_ROLES, "case")
    if role in {"cover", "closing"}:
        role = "case"
    layout = _safe_token(_layout_for_role(role, " ".join([subtitle, body]), bullets), ALLOWED_LAYOUTS, "text_focus")
    return {
        "slide_id": f"slide-{page_no}",
        "page": page_no,
        "page_label": f"{page_no:02d} / {total_pages:02d}",
        "role": role,
        "layout": layout,
        "title": title,
        "subtitle": subtitle,
        "body": body,
        "bullets": bullets,
        "links": _normalize_links(
            spec.get("links")
            or spec.get("hyperlinks")
            or spec.get("hyperlink")
            or spec.get("link")
            or spec.get("reference_link")
            or spec.get("reference_url")
            or spec.get("url")
        ),
        "badge": _role_badge(role),
        "image_refs": _strings(spec.get("image_refs")),
        "character_hint": _clean(spec.get("character_hint")),
        "character": {},
    }


def _closing_slide(page_no: int, total_pages: int, request: dict[str, Any], spec: dict[str, Any]) -> dict[str, Any]:
    """마지막 페이지는 CTA와 마무리 메시지가 중심인 별도 템플릿으로 고정합니다."""

    closing = _dict(request.get("closing"))
    cta = _dict(closing.get("cta"))
    title = _clean(spec.get("title")) or _clean(closing.get("title"))
    subtitle = _clean(spec.get("subtitle") or spec.get("sub_title") or closing.get("subtitle") or closing.get("summary"))
    # 마지막 페이지에 긴 소제목만 들어온 경우, 이를 큰 제목으로 올리면 화면이 쉽게 깨집니다.
    # 긴 문장은 소제목으로 내리고 제목은 짧은 기본 문구로 둡니다.
    if title and not subtitle and len(title) >= 28:
        subtitle = title
        title = ""
    return {
        "slide_id": f"slide-{page_no}",
        "page": page_no,
        "page_label": f"{page_no:02d} / {total_pages:02d}",
        "role": "closing",
        "layout": "closing",
        "title": title or "이번 달 마무리",
        "subtitle": subtitle,
        "body": _clean_preserve(spec.get("body") or spec.get("content")) or _clean_preserve(closing.get("body") or closing.get("content")) or "더 자세한 내용은 안내 링크를 확인해주세요.",
        "bullets": _strings(spec.get("bullets")),
        "links": _normalize_links(
            spec.get("links")
            or spec.get("hyperlinks")
            or spec.get("hyperlink")
            or spec.get("link")
            or closing.get("links")
            or closing.get("hyperlinks")
            or closing.get("hyperlink")
            or closing.get("link")
            or closing.get("reference_url")
            or closing.get("url")
        ),
        "badge": "마무리",
        "image_refs": _strings(spec.get("image_refs") or closing.get("image_ref")),
        "cta": {
            "label": _clean(cta.get("label")) or "처음으로",
            "url": _clean(cta.get("url")),
        },
        "character": {},
    }


def _image_for_page(
    page_no: int,
    total_pages: int,
    placements: dict[int, list[dict[str, Any]]],
    image_assets: dict[str, dict[str, Any]],
    role: str,
    layout: str,
) -> dict[str, Any]:
    """해당 페이지에 배정된 첫 번째 이미지를 계획에 붙입니다."""

    page_placements = placements.get(page_no, [])
    if not page_placements:
        return {}
    placement = page_placements[0]
    asset = image_assets.get(_clean(placement.get("image_id")), {})
    if not asset:
        return {}
    mode = _clean(placement.get("mode")) or _default_image_mode(page_no, total_pages, role, layout)
    return {
        "image_id": asset["image_id"],
        "data_uri": asset.get("data_uri", ""),
        "alt": _clean(placement.get("alt")) or _clean(asset.get("alt")) or "카드뉴스 이미지",
        "mode": mode,
        "fit": _safe_token(placement.get("fit"), {"contain", "cover", "fill"}, "contain"),
        "filename": asset.get("filename", ""),
        "width": asset.get("width", 0),
        "height": asset.get("height", 0),
    }


def _select_character(
    slide: dict[str, Any],
    assets: list[dict[str, Any]],
    role_defaults: dict[str, Any],
    used_ids: list[str],
) -> dict[str, Any]:
    """역할/힌트/반복 여부를 점수화해서 가장 알맞은 캐릭터를 고릅니다."""

    if not assets:
        return {}
    role = _clean(slide.get("role"))
    hint = _clean(slide.get("character_hint")).lower()
    text = " ".join([role, _clean(slide.get("title")), _clean(slide.get("body")), hint]).lower()
    defaults = _strings(role_defaults.get(role))
    scored = []
    for index, asset in enumerate(assets):
        asset_id = _clean(asset.get("asset_id"))
        ai_context = _clean(asset.get("ai_context")).lower()
        score = 0
        if role in _strings(asset.get("recommended_slide_roles")):
            score += 5
        if asset_id in defaults:
            score += max(1, 5 - defaults.index(asset_id))
        if hint and hint in ai_context:
            score += 4
        if role in {"security"} and "security" in ai_context:
            score += 5
        if role in {"tip", "checklist", "workflow"} and any(token in ai_context for token in ("helper", "tip", "automation")):
            score += 3
        if role == "closing" and any(token in ai_context for token in ("cta", "closing", "cover")):
            score += 3
        if any(word.lower() in text for word in SECURITY_WORDS) and "security" in ai_context:
            score += 4
        if asset_id in used_ids[-1:]:
            score -= 3
        scored.append((score, -index, asset))
    scored.sort(key=lambda item: (item[0], item[1]), reverse=True)
    selected = deepcopy(scored[0][2])
    return {
        "asset_id": _clean(selected.get("asset_id")),
        "character_key": _clean(selected.get("character_key")),
        "pose": _clean(selected.get("pose")),
        "data_uri": _clean(selected.get("data_uri")),
        "alt": _clean(selected.get("alt") or selected.get("display_name")) or "카드뉴스 캐릭터",
    }


def _character_placement(slide: dict[str, Any], image: dict[str, Any]) -> str:
    """슬라이드 역할에 맞는 캐릭터 위치를 정합니다."""

    role = _clean(slide.get("role"))
    if role == "cover":
        return "bottom_right"
    if role == "closing":
        return "bottom_right"
    # 본문 페이지에서는 이미지 유무와 무관하게 오른쪽 빈 공간에 캐릭터를 둡니다.
    return "right_side"


def _character_size(slide: dict[str, Any]) -> str:
    role = _clean(slide.get("role"))
    if role in {"cover", "closing"}:
        return "large"
    return "small"


def _infer_role(title: str, body: str, bullets: list[str], page_no: int) -> str:
    text = " ".join([title, body, " ".join(bullets)]).lower()
    title_body = " ".join([title, body]).lower()
    security_score = sum(1 for word in SECURITY_WORDS if word.lower() in text)
    if page_no == 2 and ("왜" in title or "why" in title.lower()):
        return "why"
    if any(word.lower() in title_body for word in SECURITY_WORDS) or security_score >= 2:
        return "security"
    if any(word.lower() in text for word in TIP_WORDS):
        return "tip" if not bullets else "checklist"
    if any(word.lower() in text for word in WORKFLOW_WORDS):
        return "workflow"
    if any(word.lower() in text for word in METRIC_WORDS):
        return "metric"
    if page_no == 2:
        return "why"
    return "case"


def _layout_for_role(role: str, body: str, bullets: list[str]) -> str:
    if role == "security":
        return "notice"
    if role in {"tip", "checklist"} or bullets:
        return "checklist"
    if role == "metric":
        return "metric"
    if len(body) > 260:
        return "text_focus"
    return "text_focus"


def _layout_with_image(role: str, layout: str, image: dict[str, Any]) -> str:
    mode = _clean(image.get("mode"))
    if role == "cover":
        return "cover"
    if role == "closing":
        return "closing"
    if mode in {"image_focus", "cover_background"}:
        return "image_focus"
    if mode in {"content_area", "side_image"} and layout in {"checklist", "notice", "metric", "text_focus"}:
        return layout
    return "text_focus"


def _default_image_mode(page_no: int, total_pages: int, role: str, layout: str) -> str:
    if page_no == 1:
        return "cover_hero"
    if page_no == total_pages:
        return "closing_hero"
    if role == "metric":
        return "image_focus"
    return "content_area"


def _page_spec_map(request: dict[str, Any]) -> dict[int, dict[str, Any]]:
    result: dict[int, dict[str, Any]] = {}
    for item in _list(request.get("pages")):
        if isinstance(item, dict):
            page = _positive_int(item.get("page"), 0)
            if page:
                result[page] = deepcopy(item)
    return result


def _image_asset_map(payload: dict[str, Any]) -> dict[str, dict[str, Any]]:
    result = {}
    for asset in _list(_dict(payload.get("image_assets")).get("assets")):
        if isinstance(asset, dict) and _clean(asset.get("image_id")):
            result[_clean(asset.get("image_id"))] = deepcopy(asset)
    return result


def _placements_by_page(payload: dict[str, Any]) -> dict[int, list[dict[str, Any]]]:
    result: dict[int, list[dict[str, Any]]] = {}
    for item in _list(payload.get("image_placements")):
        if not isinstance(item, dict):
            continue
        page = _positive_int(item.get("page"), 0)
        if page:
            result.setdefault(page, []).append(deepcopy(item))
    return result


def _character_assets(manifest: dict[str, Any]) -> list[dict[str, Any]]:
    assets = []
    for asset in _list(manifest.get("assets")):
        if isinstance(asset, dict) and _clean(asset.get("asset_id")) and _clean(asset.get("data_uri")):
            assets.append(deepcopy(asset))
    return assets


def _issue_badge(request: dict[str, Any]) -> str:
    parts = [_clean(request.get("issue_label")), _clean(request.get("issue_no"))]
    return " / ".join(part for part in parts if part) or "AI NEWS"


def _role_badge(role: str) -> str:
    return {
        "why": "WHY",
        "case": "사례",
        "tip": "TIP",
        "checklist": "CHECK",
        "security": "보안",
        "workflow": "흐름",
        "metric": "지표",
        "recap": "요약",
    }.get(role, "핵심")


def _safe_token(value: Any, allowed: set[str], default: str) -> str:
    text = _clean(value).lower().replace("-", "_")
    return text if text in allowed else default


def _merge_trace(trace_value: Any, warnings: list[str], errors: list[str]) -> dict[str, Any]:
    trace = _dict(trace_value)
    trace["warnings"] = _dedupe([*_list(trace.get("warnings")), *warnings])
    trace["errors"] = _dedupe([*_list(trace.get("errors")), *errors])
    return trace


def _payload(value: Any) -> dict[str, Any]:
    data = getattr(value, "data", value)
    return deepcopy(data) if isinstance(data, dict) else {}


def _dict(value: Any) -> dict[str, Any]:
    return deepcopy(value) if isinstance(value, dict) else {}


def _list(value: Any) -> list[Any]:
    return deepcopy(value) if isinstance(value, list) else []


def _strings(value: Any) -> list[str]:
    raw_items = value if isinstance(value, list) else ([value] if value not in (None, "") else [])
    return _dedupe(_clean(item) for item in raw_items)


def _normalize_links(value: Any) -> list[dict[str, str]]:
    """슬라이드 계획에 넣을 링크를 [{label, url}]로 통일합니다."""

    if value in (None, ""):
        return []
    if isinstance(value, dict):
        if any(key in value for key in ("url", "href", "link")):
            raw_items = [value]
        else:
            raw_items = [{"label": label, "url": url} for label, url in value.items()]
    elif isinstance(value, list):
        raw_items = value
    else:
        raw_items = [part for part in str(value).splitlines() if part.strip()]

    result: list[dict[str, str]] = []
    seen: set[str] = set()
    for item in raw_items:
        link = _coerce_link(item)
        if not link or link["url"] in seen:
            continue
        seen.add(link["url"])
        result.append(link)
    return result[:3]


def _coerce_link(item: Any) -> dict[str, str]:
    """dict/문자열 링크를 안전한 링크 dict로 바꿉니다."""

    if isinstance(item, dict):
        url = _clean(item.get("url") or item.get("href") or item.get("link"))
        label = _clean(item.get("label") or item.get("text") or item.get("title") or item.get("name")) or url
        return {"label": label, "url": url} if _safe_url(url) else {}

    text = _clean(item)
    if not text:
        return {}
    markdown = re.match(r"^\[([^\]]+)\]\((https?://[^)\s]+)\)$", text, flags=re.IGNORECASE)
    if markdown:
        url = _trim_url(markdown.group(2))
        return {"label": markdown.group(1).strip(), "url": url} if _safe_url(url) else {}

    url_match = re.search(r"https?://[^\s,;|)>\]]+", text, flags=re.IGNORECASE)
    if not url_match:
        return {}
    url = _trim_url(url_match.group(0))
    label = (text[: url_match.start()] + text[url_match.end() :]).strip(" \t-–—:：|,;()[]")
    return {"label": label or url, "url": url} if _safe_url(url) else {}


def _safe_url(value: str) -> bool:
    lowered = _clean(value).lower()
    return lowered.startswith("http://") or lowered.startswith("https://")


def _trim_url(value: str) -> str:
    return _clean(value).rstrip(".,;:!?)］】")


def _dedupe(items: Any) -> list[str]:
    result: list[str] = []
    for item in items:
        text = _clean(item)
        if text and text not in result:
            result.append(text)
    return result


def _positive_int(value: Any, default: int) -> int:
    try:
        parsed = int(value)
    except Exception:
        return default
    return max(0, parsed)


def _clean(value: Any) -> str:
    return str(value or "").strip()


def _clean_preserve(value: Any) -> str:
    text = str(value or "").strip()
    return re.sub(r"\n{3,}", "\n\n", text)


class CardNewsDeckPlanner(Component):
    """전체 카드뉴스 덱 계획을 만드는 Langflow 노드입니다."""

    display_name = "02 카드뉴스 전체 덱 기획"
    description = "첫/중간/마지막 페이지 템플릿을 나누고, 이미지와 캐릭터를 겹치지 않게 자동 배치합니다."
    icon = "LayoutTemplate"
    name = "CardNewsDeckPlanner"

    inputs = [
        DataInput(name="image_payload", display_name="이미지 포함 payload", required=True),
        MessageTextInput(
            name="character_placement_mode",
            display_name="캐릭터 배치 방식",
            value="auto_rule",
            info="auto_rule을 권장합니다. manual이면 입력 plan의 캐릭터 배치를 그대로 쓰는 확장용입니다.",
            required=False,
            advanced=True,
        ),
    ]
    outputs = [Output(name="card_news_plan", display_name="카드뉴스 전체 계획", method="build_payload", types=["Data"])]

    def build_payload(self) -> Data:
        result = build_card_news_deck_plan(
            getattr(self, "image_payload", None),
            getattr(self, "character_placement_mode", "auto_rule"),
        )
        plan = _dict(result.get("card_news_plan"))
        self.status = {
            "제목": plan.get("title"),
            "페이지 수": plan.get("page_count"),
            "캐릭터 사용 수": len(_list(plan.get("used_character_assets"))),
            "이동 방식": _dict(plan.get("navigation")).get("mode"),
        }
        return Data(data=result)

from __future__ import annotations

"""04 HTML 출력 노드.

생성된 HTML 결과를 사용자가 확인하기 쉬운 요약 메시지와
코드 블록 형태의 HTML 원문으로 나눠 출력합니다.
"""

import json
from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, MessageTextInput, Output
from lfx.schema.message import Message


def build_summary_message(html_payload_value: Any) -> str:
    """카드뉴스 생성 결과 요약을 한국어 메시지로 만듭니다."""

    payload = _payload(html_payload_value)
    plan = _dict(payload.get("card_news_plan"))
    result = _dict(payload.get("html_result"))
    trace = _dict(payload.get("trace"))
    status = _clean(result.get("status")) or "unknown"
    title = _clean(result.get("title")) or _clean(plan.get("title")) or "카드뉴스"
    lines = [
        "카드뉴스 ver2 HTML 생성 결과",
        "",
        f"- 상태: {status}",
        f"- 제목: {title}",
        f"- 페이지 수: {result.get('page_count') or plan.get('page_count')}",
        f"- 파일명 힌트: {_clean(result.get('filename_hint'))}.html",
        f"- HTML 크기: {len(_clean(result.get('html')).encode('utf-8')):,} bytes",
    ]
    used_assets = _list(plan.get("used_character_assets"))
    if used_assets:
        lines.append(f"- 사용 캐릭터: {', '.join(str(item) for item in used_assets)}")
    warnings = _list(result.get("warnings")) or _list(trace.get("warnings"))
    if warnings:
        lines.append("")
        lines.append("경고")
        lines.extend(f"- {warning}" for warning in warnings[:6])
    security = _dict(result.get("security_report"))
    if security:
        lines.append("")
        lines.append(f"보안 검사: {'통과' if security.get('passed') else '실패'}")
        violations = _list(security.get("violations"))
        if violations:
            lines.append(f"- 위반 항목: {', '.join(str(item) for item in violations)}")
    return "\n".join(lines)


def build_html_source_message(html_payload_value: Any, output_mode: Any = "code_block") -> str:
    """HTML 원문을 code block 또는 raw 형태로 출력합니다."""

    payload = _payload(html_payload_value)
    result = _dict(payload.get("html_result"))
    html_source = _clean(result.get("html"))
    mode = _clean(output_mode).lower()
    if mode in {"raw", "plain"}:
        return html_source
    if not html_source:
        return "```html\n\n```"
    escaped = html_source.replace("```", "`\u200b``")
    return f"```html\n{escaped}\n```"


def _payload(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return deepcopy(value)
    data = getattr(value, "data", None)
    if isinstance(data, dict):
        return deepcopy(data)
    text = getattr(value, "text", None) or getattr(value, "content", None)
    if isinstance(text, str) and text.strip():
        try:
            parsed = json.loads(text)
        except Exception:
            return {"text": text}
        return deepcopy(parsed) if isinstance(parsed, dict) else {"text": text}
    return {}


def _dict(value: Any) -> dict[str, Any]:
    return deepcopy(value) if isinstance(value, dict) else {}


def _list(value: Any) -> list[Any]:
    return deepcopy(value) if isinstance(value, list) else []


def _clean(value: Any) -> str:
    return str(value or "").strip()


class CardNewsHtmlOutput(Component):
